+// ──────────────── EBR properties ────────────────
+
+proptest! {
+    #![proptest_config(ProptestConfig::with_cases(64))]
+
+    /// Every retired item is eventually reclaimed after sufficient advances.
+    #[test]
+    fn ebr_all_retired_eventually_reclaimed(count in 1usize..100) {
